import { describe, expect, it } from "vitest";
import { extractSkillFromPrompt } from "./userPromptSubmit.js";
describe("extractSkillFromPrompt", () => {
    it("matches Claude Code style /bitfab:setup", () => {
        expect(extractSkillFromPrompt("/bitfab:setup")).toBe("setup");
        expect(extractSkillFromPrompt("/bitfab:assistant")).toBe("assistant");
        expect(extractSkillFromPrompt("/bitfab:update")).toBe("update");
    });
    it("matches Cursor style /bitfab-setup", () => {
        expect(extractSkillFromPrompt("/bitfab-setup")).toBe("setup");
        expect(extractSkillFromPrompt("/bitfab-assistant")).toBe("assistant");
        expect(extractSkillFromPrompt("/bitfab-update")).toBe("update");
    });
    it("captures skill name when arguments are passed", () => {
        expect(extractSkillFromPrompt("/bitfab:setup instrument")).toBe("setup");
        expect(extractSkillFromPrompt("/bitfab:setup replay")).toBe("setup");
        expect(extractSkillFromPrompt("/bitfab-assistant memory-search")).toBe("assistant");
    });
    it("ignores leading whitespace", () => {
        expect(extractSkillFromPrompt("  /bitfab:setup")).toBe("setup");
    });
    it("is case-insensitive on the skill name", () => {
        expect(extractSkillFromPrompt("/bitfab:SETUP")).toBe("setup");
        expect(extractSkillFromPrompt("/BITFAB:assistant")).toBe("assistant");
    });
    it("returns null for non-Bitfab slash commands", () => {
        expect(extractSkillFromPrompt("/help")).toBeNull();
        expect(extractSkillFromPrompt("/peek:login")).toBeNull();
        expect(extractSkillFromPrompt("/bitfab:unknown")).toBeNull();
    });
    it("returns null for plain text prompts that mention /bitfab:setup mid-sentence", () => {
        expect(extractSkillFromPrompt("remind me how to use /bitfab:setup later")).toBeNull();
    });
    it("returns null for empty prompts", () => {
        expect(extractSkillFromPrompt("")).toBeNull();
        expect(extractSkillFromPrompt("   ")).toBeNull();
    });
    it("requires a word boundary after the skill name", () => {
        // "/bitfab:setupfoo" must not be treated as the setup skill.
        expect(extractSkillFromPrompt("/bitfab:setupfoo")).toBeNull();
    });
});
